```class Solution:
    def answerString(self, word: str, numFriends: int) -> str:
        def backtrack(start, path):
            if start == len(word):
                res.append(path)
                return
            for i in range(numFriends, 0, -1):
                if start + i <= len(word):
                    backtrack(start + i, path + word[start:start + i])
        res = []
        backtrack(0, "")
        return max(res)
```

